const SUPABASE_URL = '<OPTIMAL_SUPABASE_URL>';
const SUPABASE_KEY = '<OPTIMAL_SUPABASE_SERVICE_KEY>';
const GROQ_KEY = '<GROQ_API_KEY>';
const CAMPAIGN_ID = '46189a3a-f75b-4811-9e93-efaf252956d6';

// Step 1: Fetch insights from the last 7 days
const since = new Date(Date.now() - 7 * 86400000).toISOString();
const insightsRes = await fetch(
  `${SUPABASE_URL}/rest/v1/content_insights?topic=eq.openclaw&created_at=gte.${since}&order=created_at.desc&limit=7`,
  { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` } }
);
const insights = await insightsRes.json();

if (!insights.length) {
  return [{ json: { skipped: true, message: 'No insights in last 7 days' } }];
}

// Step 2: Combine insights into a prompt
const insightSummaries = insights.map((ins, i) => {
  const themes = Array.isArray(ins.key_themes) ? ins.key_themes.join(', ') : '';
  return `Day ${i + 1} (${ins.source_count} sources):\n${ins.summary}\nThemes: ${themes}`;
}).join('\n\n---\n\n');

const systemPrompt = `You write engaging Facebook posts for Optimal Tech Corp — a Miami-based AI consulting company. 
Your tone is confident, technically grounded, and internet-native.
Write a medium-length Facebook post (150-300 words) summarizing the week's developments.
Include specific details, numbers, and links where relevant.
End with a question or call-to-action to drive engagement.
Return ONLY the post text, no JSON wrapping.`;

const userPrompt = `Based on these ${insights.length} daily intelligence digests from the past week, write a Facebook post:\n\n${insightSummaries}`;

// Step 3: Call Groq
const groqRes = await fetch('https://api.groq.com/openai/v1/chat/completions', {
  method: 'POST',
  headers: {
    Authorization: `Bearer ${GROQ_KEY}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    temperature: 0.7,
    max_tokens: 1000,
  })
});

const groqData = await groqRes.json();
if (groqData.error) {
  return [{ json: { error: 'Groq API error: ' + JSON.stringify(groqData.error) } }];
}

let content = groqData.choices?.[0]?.message?.content || '';
// Strip any accidental JSON wrapping
content = content.replace(/^```[\s\S]*?\n/, '').replace(/\n```$/, '').trim();

// Step 4: Save to content_generated_posts
const post = {
  campaign_id: CAMPAIGN_ID,
  insight_id: insights[0].id,
  platform: 'facebook',
  content: content,
  hashtags: [],
  status: 'draft',
  model_used: 'groq/llama-3.3-70b',
};

const saveRes = await fetch(
  `${SUPABASE_URL}/rest/v1/content_generated_posts`,
  {
    method: 'POST',
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      Prefer: 'return=representation',
    },
    body: JSON.stringify(post),
  }
);

if (!saveRes.ok) {
  const errText = await saveRes.text();
  return [{ json: { error: `Save failed (${saveRes.status}): ${errText}` } }];
}

const saved = await saveRes.json();
return [{ json: { post_id: saved[0]?.id, platform: 'facebook', status: 'draft', content_preview: content.substring(0, 200) } }];
